// ═══════════════════════════════════════════════════════════
// Object State Machine Engine
// ═══════════════════════════════════════════════════════════
//
// Objects are defined as JSON with state machines. Each state can have:
//   - visual: string descriptor for renderer
//   - particles: optional particle effect name
//   - emoji: optional emoji to float on enter
//   - auto_next: { state, after (seconds) } — timed auto-transition
//   - transitions: { action_name: { next, duration?, requires?, produces?, target? } }
//
// The engine ticks all objects, advancing auto_next timers.
// Characters trigger transitions via interact(objectId, action).

export class ObjectInstance {
  constructor(def) {
    this.id = def.id;
    this.name = def.name;
    this.sector = def.sector;
    this.arena = def.arena;
    this.position = { ...def.position };
    this.states = def.states;
    this.state = def.state || Object.keys(def.states)[0];
    this.timer = 0; // ms elapsed in current state
    this.autoNextDuration = this._getAutoNextDuration(); // ms until auto-transition (null if none)
  }

  _getAutoNextDuration() {
    const stateDef = this.states[this.state];
    if (stateDef?.auto_next) {
      return stateDef.auto_next.after * 1000; // convert seconds → ms
    }
    return null;
  }

  get currentStateDef() {
    return this.states[this.state];
  }

  get visual() {
    return this.currentStateDef?.visual || this.state;
  }

  get particles() {
    return this.currentStateDef?.particles || null;
  }

  get timeRemainingMs() {
    if (this.autoNextDuration === null) return null;
    return Math.max(0, this.autoNextDuration - this.timer);
  }

  // Returns a transition event if auto_next fires, or null
  tick(deltaMs) {
    if (this.autoNextDuration === null) return null;

    this.timer += deltaMs;

    if (this.timer >= this.autoNextDuration) {
      const autoNext = this.currentStateDef.auto_next;
      return this._transition(autoNext.state, 'auto');
    }

    return null;
  }

  // Attempt a character-triggered interaction.
  // Returns a transition event, or null if no valid transition.
  interact(action = 'use') {
    const stateDef = this.currentStateDef;
    if (!stateDef?.transitions) return null;

    const transition = stateDef.transitions[action];
    if (!transition) return null;

    // If the transition requires a character, that's expected (caller is a character)
    return this._transition(transition.next, action, transition);
