#!/usr/bin/env node
// ═══════════════════════════════════════════════════════════
// Sprite Generator — 16×16 pixel art for AI Aquarium
// ═══════════════════════════════════════════════════════════
// Usage: node scripts/generate-sprites.js
// Creates assets/tiles/*.png, assets/objects/*.png, assets/characters/*.png

import { createCanvas } from 'canvas';
import { writeFileSync, mkdirSync } from 'fs';
import { join, dirname } from 'path';
import { fileURLToPath } from 'url';

const __dirname = dirname(fileURLToPath(import.meta.url));
const ROOT = join(__dirname, '..');
const SIZE = 16;

// ── Helpers ──

function makeCanvas() {
  const c = createCanvas(SIZE, SIZE);
  const ctx = c.getContext('2d');
  ctx.imageSmoothingEnabled = false;
  return { c, ctx };
}

function save(subdir, name, canvas) {
  const dir = join(ROOT, 'assets', subdir);
  mkdirSync(dir, { recursive: true });
  const path = join(dir, name + '.png');
  writeFileSync(path, canvas.toBuffer('image/png'));
  console.log(`  ✓ ${subdir}/${name}.png`);
}

function px(ctx, x, y, color) {
  ctx.fillStyle = color;
  ctx.fillRect(x, y, 1, 1);
}

function fill(ctx, color) {
  ctx.fillStyle = color;
  ctx.fillRect(0, 0, SIZE, SIZE);
}

function rect(ctx, x, y, w, h, color) {
  ctx.fillStyle = color;
  ctx.fillRect(x, y, w, h);
}

// Draw from a 16x16 pixel map (array of strings, each char = color key)
function drawMap(ctx, map, palette) {
  for (let y = 0; y < map.length && y < SIZE; y++) {
    const row = map[y];
    for (let x = 0; x < row.length && x < SIZE; x++) {
      const ch = row[x];
      if (ch === ' ' || ch === '.') continue; // transparent
      const color = palette[ch];
      if (color) px(ctx, x, y, color);
    }
  }
}

// ═══════════════════════════════════════════════════════════
// TILE SPRITES
// ═══════════════════════════════════════════════════════════

function generateTiles() {
  console.log('\n🌿 Generating tile sprites...');

  // ── grass.png ──
  {
    const { c, ctx } = makeCanvas();
    fill(ctx, '#4a7c3f');
    // Random grass texture
    const highlights = '#5a8c4f';
    const shadows = '#3a6c2f';
    const blades = [
      [2,3],[5,1],[8,6],[11,2],[14,5],[1,9],[4,12],[7,8],
      [10,11],[13,14],[3,7],[6,13],[9,4],[12,9],[15,1],
      [0,14],[7,15],[13,7],[2,11],[8,0]
    ];
    for (const [x, y] of blades) px(ctx, x, y, highlights);
    const darks = [
      [1,4],[4,0],[7,5],[10,3],[13,8],[0,12],[5,10],[8,14],
      [11,7],[14,13],[3,2],[9,9],[12,1],[6,6],[15,11]
    ];
    for (const [x, y] of darks) px(ctx, x, y, shadows);
    save('tiles', 'grass', c);
  }

  // ── path.png ──
  {
    const { c, ctx } = makeCanvas();
    fill(ctx, '#c2a86b');
    const light = '#d4ba7d';
    const dark = '#a8905a';
    const pebble = '#9a8555';
    // Subtle dirt path texture
    for (const [x, y] of [[2,2],[6,5],[10,3],[14,7],[4,11],[8,14],[12,10],[1,6],[9,1],[15,13]]) {
      px(ctx, x, y, light);
    }

