// ═══════════════════════════════════════════════════════════
// CHARACTER SPRITES
// ═══════════════════════════════════════════════════════════

function generateCharacters() {
  console.log('\n🧑 Generating character sprites...');

  // Character design helper — top-down 16x16 characters
  function drawCharacter(name, colors, variant = 'idle') {
    const { c, ctx } = makeCanvas();
    const { hair, hairDark, skin, shirt, shirtDark, pants, shoes, accessory } = colors;

    // All characters face downward (top-down perspective, head at top)
    if (variant === 'idle') {
      // Hair/head (rows 2-5)
      rect(ctx, 5, 1, 6, 1, hairDark);
      rect(ctx, 4, 2, 8, 2, hair);
      rect(ctx, 5, 4, 6, 1, hair);
      // Face
      px(ctx, 6, 3, skin); px(ctx, 7, 3, skin); px(ctx, 8, 3, skin); px(ctx, 9, 3, skin);
      px(ctx, 6, 4, skin); px(ctx, 7, 4, skin); px(ctx, 8, 4, skin); px(ctx, 9, 4, skin);
      // Eyes
      px(ctx, 6, 3, '#2a2a2a'); px(ctx, 9, 3, '#2a2a2a');
      // Body/shirt (rows 5-9)
      rect(ctx, 5, 5, 6, 5, shirt);
      px(ctx, 5, 5, shirtDark); px(ctx, 10, 5, shirtDark);
      px(ctx, 5, 9, shirtDark); px(ctx, 10, 9, shirtDark);
      // Arms
      rect(ctx, 3, 6, 2, 3, shirt);
      rect(ctx, 11, 6, 2, 3, shirt);
      px(ctx, 3, 8, skin); px(ctx, 4, 8, skin);
      px(ctx, 11, 8, skin); px(ctx, 12, 8, skin);
      // Pants (rows 10-12)
      rect(ctx, 5, 10, 6, 3, pants);
      px(ctx, 7, 10, pants); px(ctx, 8, 10, pants);
      // Shoes (rows 13-14)
      rect(ctx, 5, 13, 3, 1, shoes);
      rect(ctx, 8, 13, 3, 1, shoes);
      // Accessory
      if (accessory) {
        // Hat/headband
        rect(ctx, 4, 1, 8, 1, accessory);
      }
    } else if (variant === 'walk1') {
      // Walking frame 1 - left foot forward
      // Hair/head
      rect(ctx, 5, 1, 6, 1, hairDark);
      rect(ctx, 4, 2, 8, 2, hair);
      rect(ctx, 5, 4, 6, 1, hair);
      px(ctx, 6, 3, skin); px(ctx, 7, 3, skin); px(ctx, 8, 3, skin); px(ctx, 9, 3, skin);
      px(ctx, 6, 4, skin); px(ctx, 7, 4, skin); px(ctx, 8, 4, skin); px(ctx, 9, 4, skin);
      px(ctx, 6, 3, '#2a2a2a'); px(ctx, 9, 3, '#2a2a2a');
      // Body
      rect(ctx, 5, 5, 6, 5, shirt);
      px(ctx, 5, 5, shirtDark); px(ctx, 10, 5, shirtDark);
      // Arms swinging
      rect(ctx, 3, 5, 2, 3, shirt); // left arm forward
      rect(ctx, 11, 7, 2, 3, shirt); // right arm back
      px(ctx, 3, 7, skin); px(ctx, 4, 7, skin);
      px(ctx, 11, 9, skin); px(ctx, 12, 9, skin);
      // Legs - left forward
      rect(ctx, 4, 10, 3, 3, pants);
      rect(ctx, 9, 10, 3, 2, pants);
      rect(ctx, 4, 13, 3, 1, shoes);
      rect(ctx, 9, 12, 3, 1, shoes);
      if (accessory) rect(ctx, 4, 1, 8, 1, accessory);
    } else if (variant === 'walk2') {
      // Walking frame 2 - right foot forward
      rect(ctx, 5, 1, 6, 1, hairDark);
      rect(ctx, 4, 2, 8, 2, hair);
      rect(ctx, 5, 4, 6, 1, hair);
      px(ctx, 6, 3, skin); px(ctx, 7, 3, skin); px(ctx, 8, 3, skin); px(ctx, 9, 3, skin);
      px(ctx, 6, 4, skin); px(ctx, 7, 4, skin); px(ctx, 8, 4, skin); px(ctx, 9, 4, skin);
      px(ctx, 6, 3, '#2a2a2a'); px(ctx, 9, 3, '#2a2a2a');
      // Body
      rect(ctx, 5, 5, 6, 5, shirt);
      px(ctx, 5, 5, shirtDark); px(ctx, 10, 5, shirtDark);
      // Arms swinging (opposite of walk1)
