      rect(ctx, 8, 10, 3, 3, pants);
      rect(ctx, 5, 12, 3, 1, shoes);
      rect(ctx, 8, 13, 3, 1, shoes);
      if (accessory) rect(ctx, 4, 1, 8, 1, accessory);
    }

    save('characters', `${name}_${variant}`, c);
  }

  // Maple — baker (warm reds, apron white)
  const mapleColors = {
    hair: '#c06030',
    hairDark: '#a04820',
    skin: '#e0b898',
    shirt: '#e04040',
    shirtDark: '#c03030',
    pants: '#604030',
    shoes: '#4a3020',
