  };
  drawCharacter('maple', mapleColors, 'idle');
  drawCharacter('maple', mapleColors, 'walk1');
  drawCharacter('maple', mapleColors, 'walk2');

  // Sol — gardener (greens, earth tones)
  const solColors = {
    hair: '#4a3020',
