    shirt: '#408040',
    shirtDark: '#306030',
    pants: '#6a5a40',
    shoes: '#5a4a30',
    accessory: '#c0a060', // straw hat
  };
  drawCharacter('sol', solColors, 'idle');
  drawCharacter('sol', solColors, 'walk1');
  drawCharacter('sol', solColors, 'walk2');

  // Nyx — artist (purple, dark tones)
  const nyxColors = {
    hair: '#3a2050',
