const DEFAULT_OBJ_COLOR = '#ff00ff';

// ── Particle definitions ──
const PARTICLE_DEFS = {
  small_steam:  { color: '#cccccc', size: 2, count: 3, speed: 0.3, life: 800, wobble: true },
  steam:        { color: '#dddddd', size: 3, count: 5, speed: 0.4, life: 1000, wobble: true },
