// Quick logic test: verify getInteractAnim mapping
class SimulationEngine {
  static _getInteractAnim(objectId) {
    if (!objectId) return null;
    if (objectId.includes('book') || objectId.includes('desk') || objectId.includes('bookshelf')) {
      return 'reading';
    }
    if (objectId.includes('bed') || objectId.includes('kotatsu') || objectId.includes('sofa') || objectId.includes('tv')) {
      return 'sit';
    }
    return 'phone';
  }
}

const tests = [
  ['cafe_book', 'reading'],
  ['apt_desk', 'reading'],
  ['apt_bookshelf', 'reading'],
  ['apt_bed', 'sit'],
  ['kotatsu_1', 'sit'],
  ['living_tv', 'sit'],
  ['apt_stove', 'phone'],
  ['apt_fridge', 'phone'],
  ['apt_easel', 'phone'],
  ['cafe_espresso', 'phone'],
  ['cafe_register', 'phone'],
  ['cafe_sink', 'phone'],
  [null, null],
];

let allOk = true;
for (const [id, expected] of tests) {
  const got = SimulationEngine._getInteractAnim(id);
  const ok = got === expected;
  console.log(`${ok ? '✅' : '❌'} ${id} → ${got} (expected ${expected})`);
  if (!ok) allOk = false;
}
console.log(allOk ? '\n✅ All mapping tests pass' : '\n❌ Some tests failed');
EOF
